_COMBINE_SPEC_OVERRIDES: dict[str, dict[str, object]] = {
    "rGDP": {
        "priority": "IMF_WEO BCEAO AMF EUS OECD_EO WDI IMF_IFS WDI_ARC ADB MW UN FAO AMECO CS1 CS2 CS3 JST BORDO MD NBS GNA AHSTAT BARRO BG MAD Mitchell HFS",
        "method": "chainlink",
        "base_year": 2018,
    },
}


@lru_cache(maxsize=1)
def _load_pipeline_specs() -> dict[str, object]:
    specs = json.loads(PIPELINE_SPECS_JSON)
    combine_entries = specs.get("combine", [])
    if isinstance(combine_entries, list):
        for entry in combine_entries:
            if not isinstance(entry, dict):
                continue
            target = str(entry.get("target", ""))
            override = _COMBINE_SPEC_OVERRIDES.get(target)
            if override is None:
                continue
            entry["spec"] = copy.deepcopy(override)
    return specs


def get_pipeline_specs() -> dict[str, object]:
    return copy.deepcopy(_load_pipeline_specs())


__all__ = ["get_pipeline_specs"]
